INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_GM2a_L1_A', 'ENG_GM2a', 1, 'A', 'Multisensory Encounter', 'Paper, Pencil', NULL, NULL, NULL, NULL, 'Variation A: Read these 3 strips aloud. Sort them into ''telling'', ''asking'', and ''exciting'' piles.', 'Child correctly identifies or produces the target grammar structure.', 'If incorrect, provide the rule simply and ask them to try again.', 'How do you know this one is a question?', '{"default":{"names":["Alex","Sam","Pat"],"settings":["park","school","store"],"food":["apples","bread","milk"]},"ug":{"names":["Amara","Tendo","Azie"],"settings":["Kampala market","village","garden"],"food":["matooke","mangoes","chapati"]}}', 0);
