INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_GM2a_L3_A', 'ENG_GM2a', 3, 'A', 'Error Detection', 'Paper, Pencil', NULL, NULL, NULL, NULL, 'Variation A: Read this sentence: ''Are we going to the park.'' What is wrong with the punctuation at the end? Fix it.', 'Child correctly identifies or produces the target grammar structure.', 'If incorrect, provide the rule simply and ask them to try again.', 'Why did you change the full stop to a question mark?', '{"default":{"names":["Alex","Sam","Pat"],"settings":["park","school","store"],"food":["apples","bread","milk"]},"ug":{"names":["Amara","Tendo","Azie"],"settings":["Kampala market","village","garden"],"food":["matooke","mangoes","chapati"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_GM2a_L3_B', 'ENG_GM2a', 3, 'B', 'Error Detection', 'Paper, Pencil', NULL, NULL, NULL, NULL, 'Variation B: Read this sentence: ''Wow, that is a huge tree?'' Find the mistake and fix it.', 'Child correctly identifies or produces the target grammar structure.', 'If incorrect, provide the rule simply and ask them to try again.', 'Why doesn''t a question mark belong there?', '{"default":{"names":["Alex","Sam","Pat"],"settings":["park","school","store"],"food":["apples","bread","milk"]},"ug":{"names":["Amara","Tendo","Azie"],"settings":["Kampala market","village","garden"],"food":["matooke","mangoes","chapati"]}}', 0);
